prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  (COUNT(DISTINCT ?choreo) AS ?choreoCount)
  (COUNT(DISTINCT ?end) AS ?endCount)
  (COUNT(DISTINCT ?start) AS ?startCount)
WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "0b21c69687b64d8886fb7cc5dc56ff6c" .
  ?model tai:belongsTo ?org .
  ?def tai:belongsTo ?model .

  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?def .

  OPTIONAL { ?start a bboExt:StartEvent ; tai:belongsTo ?choreo . }
  OPTIONAL { ?end a bboExt:EndEvent ; tai:belongsTo ?choreo . }
}

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  ?model
  ?modelName
  ?originalId
  ?normalizedId
  (COUNT(DISTINCT ?choreo) AS ?choreoCount)
WHERE {
  ?model a bboExt:Model ;
         tai:belongsTo ?org .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:originalId ?originalId . }
  OPTIONAL { ?model tai:normalizedId ?normalizedId . }

  OPTIONAL {
    ?def tai:belongsTo ?model .
    ?choreo a bboExt:Choreography ; tai:belongsTo ?def .
  }

  FILTER(
    STRENDS(STR(?originalId), "0b21c69687b64d8886fb7cc5dc56ff6c") ||
    STRENDS(STR(?normalizedId), "0b21c69687b64d8886fb7cc5dc56ff6c") ||
    STRENDS(STR(?model), "0b21c69687b64d8886fb7cc5dc56ff6c") ||
    CONTAINS(LCASE(STR(?modelName)), LCASE("0b21c69687b64d8886fb7cc5dc56ff6c"))
  )
}
GROUP BY ?model ?modelName ?originalId ?normalizedId
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?totalStartCount ?badStartCount WHERE {
  { 
    SELECT (COUNT(DISTINCT ?start) AS ?totalStartCount) WHERE {
      ?model a bboExt:Model ;
             tai:normalizedId "sid_32ebd244_789a_4034_845b_7909f514afae" .
      ?def tai:belongsTo ?model .
      ?choreo a bboExt:Choreography ; tai:belongsTo ?def .
      ?start a bboExt:StartEvent ; tai:belongsTo ?choreo .
    }
  }
  { 
    SELECT (COUNT(DISTINCT ?start) AS ?badStartCount) WHERE {
      ?model a bboExt:Model ;
             tai:normalizedId "sid_32ebd244_789a_4034_845b_7909f514afae" .
      ?def tai:belongsTo ?model .
      ?choreo a bboExt:Choreography ; tai:belongsTo ?def .

      ?start a bboExt:StartEvent ; tai:belongsTo ?choreo .

      FILTER NOT EXISTS {
        ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?anyEnd .
        ?anyEnd a bboExt:EndEvent ; tai:belongsTo ?choreo .
      }
    }
  }
}
